# Set creation and element checks
s = {1, 2, 3, 3, 3} # {1, 2, 3}
s.add(4)
s.remove(2)
s.discard(10)       # safe discard (no error if missing)

# Set Operations
a = {1, 2, 3}
b = {3, 4, 5}
union = a | b          # {1, 2, 3, 4, 5}
intersection = a & b   # {3}
difference = a - b     # {1, 2}
sym_diff = a ^ b       # {1, 2, 4, 5}

# Set Comprehension
uniq_evens = {x**2 for x in range(5) if x % 2 == 0} # {0, 16, 4}
